bool PMDC_Destroy(PMDC* me)
{
  UNITY_LINE_TYPE cmock_line = TEST_LINE_NUM;
  CMOCK_PMDC_Destroy_CALL_INSTANCE* cmock_call_instance;
  UNITY_SET_DETAIL(CMockString_PMDC_Destroy);
  cmock_call_instance = (CMOCK_PMDC_Destroy_CALL_INSTANCE*)CMock_Guts_GetAddressFor(Mock.PMDC_Destroy_CallInstance);
  Mock.PMDC_Destroy_CallInstance = CMock_Guts_MemNext(Mock.PMDC_Destroy_CallInstance);
  if (Mock.PMDC_Destroy_IgnoreBool)
  {
    UNITY_CLR_DETAILS();
    if (cmock_call_instance == NULL)
      return Mock.PMDC_Destroy_FinalReturn;
    Mock.PMDC_Destroy_FinalReturn = cmock_call_instance->ReturnVal;
    return cmock_call_instance->ReturnVal;
  }
  if (!Mock.PMDC_Destroy_CallbackBool &&
      Mock.PMDC_Destroy_CallbackFunctionPointer != NULL)
  {
    bool cmock_cb_ret = Mock.PMDC_Destroy_CallbackFunctionPointer(me, Mock.PMDC_Destroy_CallbackCalls++);
    UNITY_CLR_DETAILS();
    return cmock_cb_ret;
  }
  UNITY_TEST_ASSERT_NOT_NULL(cmock_call_instance, cmock_line, CMockStringCalledMore);
  cmock_line = cmock_call_instance->LineNumber;
  if (cmock_call_instance->CallOrder > ++GlobalVerifyOrder)
    UNITY_TEST_FAIL(cmock_line, CMockStringCalledEarly);
  if (cmock_call_instance->CallOrder < GlobalVerifyOrder)
    UNITY_TEST_FAIL(cmock_line, CMockStringCalledLate);
  if (!cmock_call_instance->IgnoreArg_me)
  {
    UNITY_SET_DETAILS(CMockString_PMDC_Destroy,CMockString_me);
    if (cmock_call_instance->Expected_me == NULL)
      { UNITY_TEST_ASSERT_NULL(me, cmock_line, CMockStringExpNULL); }
    else
      { UNITY_TEST_ASSERT_EQUAL_MEMORY_ARRAY((void*)(cmock_call_instance->Expected_me), (void*)(me), sizeof(PMDC), cmock_call_instance->Expected_me_Depth, cmock_line, CMockStringMismatch); }
  }
  if (Mock.PMDC_Destroy_CallbackFunctionPointer != NULL)
  {
    cmock_call_instance->ReturnVal = Mock.PMDC_Destroy_CallbackFunctionPointer(me, Mock.PMDC_Destroy_CallbackCalls++);
  }
  if (cmock_call_instance->ReturnThruPtr_me_Used)
  {
    UNITY_TEST_ASSERT_NOT_NULL(me, cmock_line, CMockStringPtrIsNULL);
    memcpy((void*)me, (const void*)cmock_call_instance->ReturnThruPtr_me_Val,
      cmock_call_instance->ReturnThruPtr_me_Size);
  }
  UNITY_CLR_DETAILS();
  return cmock_call_instance->ReturnVal;
}

